import { ApiPropertyOptional } from '@nestjs/swagger';
import { Type } from 'class-transformer';
import { IsIn, IsInt, IsOptional, Max, Min } from 'class-validator';

const ALLOWED_MARCH_PROMO_CATEGORY_IDS = [218, 8, 188, 521, 920, 405];

export class MarchPromoQueryDto {
	@ApiPropertyOptional({
		description: 'Number of products to return',
		example: 20,
		default: 20,
	})
	@IsOptional()
	@Type(() => Number)
	@IsInt({ message: 'Limit must be an integer' })
	@Min(1, { message: 'Limit must be greater than 0' })
	@Max(100, { message: 'Limit must be less than or equal to 100' })
	limit?: number;

	@ApiPropertyOptional({
		description:
			'Category ID to filter products. Allowed: 218 (Promotional Products), 8 (Pens & Office Supplies), 188 (Technology), 521 (Pens & Writing), 920 (Stationery), 405 (Stickers & Magnets)',
		example: 8,
		default: 8,
	})
	@IsOptional()
	@Type(() => Number)
	@IsInt({ message: 'categoryId must be an integer' })
	@IsIn(ALLOWED_MARCH_PROMO_CATEGORY_IDS, {
		message: `categoryId must be one of: ${ALLOWED_MARCH_PROMO_CATEGORY_IDS.join(', ')}`,
	})
	categoryId?: number;
}

