import { ApiProperty } from '@nestjs/swagger';
import { Type } from 'class-transformer';
import { IsArray, IsInt, ValidateNested } from 'class-validator';

import { IRelatedProduct } from '@interfaces/related-product.interface';

import { RelatedProductDto } from '@dto/related-products/related-products-response.dto';

export class PromoResponseDto {
	@ApiProperty({
		description: 'List of promo products (90% trending, 10% promotional)',
		type: [RelatedProductDto],
	})
	@IsArray({ message: 'Products must be an array' })
	@ValidateNested({ each: true })
	@Type(() => RelatedProductDto)
	products: IRelatedProduct[];

	@ApiProperty({
		description: 'Total number of products returned',
		example: 20,
	})
	@IsInt({ message: 'Total count must be an integer' })
	totalCount: number;

	@ApiProperty({
		description: 'Number of trending products included',
		example: 18,
	})
	@IsInt({ message: 'Trending count must be an integer' })
	trendingCount: number;

	@ApiProperty({
		description: 'Number of promotional products included',
		example: 2,
	})
	@IsInt({ message: 'Promotional count must be an integer' })
	promotionalCount: number;

	@ApiProperty({
		description: 'Number of boosted brand products included',
		example: 3,
	})
	@IsInt({ message: 'Boosted brand count must be an integer' })
	boostedBrandCount: number;
}

