import { Test, TestingModule } from '@nestjs/testing';

import { MarchPromoQueryDto } from '@modules/rest/promos/dto/march-promo-query.dto';
import { PromoQueryDto } from '@modules/rest/promos/dto/promo-query.dto';
import { PromoResponseDto } from '@modules/rest/promos/dto/promo-response.dto';
import { PromosController } from '@modules/rest/promos/promos.controller';
import { PromosService } from '@modules/rest/promos/promos.service';

describe('PromosController', () => {
	let controller: PromosController;
	let mockService: jest.Mocked<PromosService>;

	const mockResponseDto: PromoResponseDto = {
		products: [
			{
				color: 1521505,
				link: '/products/test-product-1',
				sizing: 'One Size',
				sizes: ['One Size'],
				min_qty: 25,
				complement_badge: null,
				rating_score: '4.5',
				rating_count: '100',
				name: 'Test Promo Product',
				style_id: 123456,
				decoration_method: 'screen',
				primary_category_id: 37,
				primary_category_name: 'Tote Bags',
				default_quote_qty: 100,
				style_type: 'non-apparel',
				image_src: 'https://example.com/product.jpg',
				broad_category_names: ['Bags', 'Promotional Products'],
				sub_category_names: ['Tote Bags', 'All Bags'],
				turn_time: 14,
				rush_turn_time: 7,
				default_unit_prices: [
					{ algorithm: 'default-2022-03-24', quantity: 100, price: '25.95' },
				],
				brand: [],
			},
		],
		totalCount: 20,
		trendingCount: 18,
		promotionalCount: 2,
		boostedBrandCount: 3,
	};

	beforeEach(async () => {
		mockService = {
			getHatPromoProducts: jest.fn(),
			getMarchPromoProducts: jest.fn(),
		} as unknown as jest.Mocked<PromosService>;

		const module: TestingModule = await Test.createTestingModule({
			controllers: [PromosController],
			providers: [
				{
					provide: PromosService,
					useValue: mockService,
				},
			],
		}).compile();

		controller = module.get<PromosController>(PromosController);
	});

	afterEach(() => {
		jest.clearAllMocks();
	});

	describe('getHatPromoProducts', () => {
		it('should return hat promo products with default parameters', async () => {
			const queryDto: PromoQueryDto = {};
			mockService.getHatPromoProducts.mockResolvedValue(mockResponseDto);

			const result = await controller.getHatPromoProducts(queryDto);

			expect(result).toEqual(mockResponseDto);
			expect(mockService.getHatPromoProducts).toHaveBeenCalledWith(undefined);
		});

		it('should return hat promo products with limit', async () => {
			const queryDto: PromoQueryDto = {
				limit: 5,
			};
			mockService.getHatPromoProducts.mockResolvedValue(mockResponseDto);

			const result = await controller.getHatPromoProducts(queryDto);

			expect(result).toEqual(mockResponseDto);
			expect(mockService.getHatPromoProducts).toHaveBeenCalledWith(5);
		});

		it('should handle service errors', async () => {
			const queryDto: PromoQueryDto = {};
			const serviceError = new Error('Service unavailable');
			mockService.getHatPromoProducts.mockRejectedValue(serviceError);

			await expect(controller.getHatPromoProducts(queryDto)).rejects.toThrow(
				'Service unavailable',
			);
			expect(mockService.getHatPromoProducts).toHaveBeenCalledWith(undefined);
		});

		it('should handle empty results', async () => {
			const queryDto: PromoQueryDto = {};
			const emptyResponse: PromoResponseDto = {
				products: [],
				totalCount: 0,
				trendingCount: 0,
				promotionalCount: 0,
				boostedBrandCount: 0,
			};
			mockService.getHatPromoProducts.mockResolvedValue(emptyResponse);

			const result = await controller.getHatPromoProducts(queryDto);

			expect(result).toEqual(emptyResponse);
			expect(result.products).toHaveLength(0);
			expect(result.totalCount).toBe(0);
			expect(mockService.getHatPromoProducts).toHaveBeenCalledWith(undefined);
		});

		it('should handle large limit values', async () => {
			const queryDto: PromoQueryDto = {
				limit: 100,
			};
			mockService.getHatPromoProducts.mockResolvedValue(mockResponseDto);

			const result = await controller.getHatPromoProducts(queryDto);

			expect(result).toEqual(mockResponseDto);
			expect(mockService.getHatPromoProducts).toHaveBeenCalledWith(100);
		});

		it('should handle edge case with limit 1', async () => {
			const queryDto: PromoQueryDto = {
				limit: 1,
			};
			const singleProductResponse: PromoResponseDto = {
				products: [mockResponseDto.products[0]!],
				totalCount: 1,
				trendingCount: 1,
				promotionalCount: 0,
				boostedBrandCount: 0,
			};
			mockService.getHatPromoProducts.mockResolvedValue(singleProductResponse);

			const result = await controller.getHatPromoProducts(queryDto);

			expect(result).toEqual(singleProductResponse);
			expect(result.products).toHaveLength(1);
			expect(mockService.getHatPromoProducts).toHaveBeenCalledWith(1);
		});
	});

	describe('getMarchPromoProducts', () => {
		it('should return march promo products with default parameters', async () => {
			const queryDto: MarchPromoQueryDto = {};
			mockService.getMarchPromoProducts.mockResolvedValue(mockResponseDto);

			const result = await controller.getMarchPromoProducts(queryDto);

			expect(result).toEqual(mockResponseDto);
			expect(mockService.getMarchPromoProducts).toHaveBeenCalledWith({
				limit: undefined,
				categoryId: undefined,
			});
		});

		it('should return march promo products with limit', async () => {
			const queryDto: MarchPromoQueryDto = { limit: 5 };
			mockService.getMarchPromoProducts.mockResolvedValue(mockResponseDto);

			const result = await controller.getMarchPromoProducts(queryDto);

			expect(result).toEqual(mockResponseDto);
			expect(mockService.getMarchPromoProducts).toHaveBeenCalledWith({
				limit: 5,
				categoryId: undefined,
			});
		});

		it('should return march promo products with categoryId', async () => {
			const queryDto: MarchPromoQueryDto = { categoryId: 188 };
			mockService.getMarchPromoProducts.mockResolvedValue(mockResponseDto);

			const result = await controller.getMarchPromoProducts(queryDto);

			expect(result).toEqual(mockResponseDto);
			expect(mockService.getMarchPromoProducts).toHaveBeenCalledWith({
				limit: undefined,
				categoryId: 188,
			});
		});

		it('should return march promo products with limit and categoryId', async () => {
			const queryDto: MarchPromoQueryDto = { limit: 10, categoryId: 521 };
			mockService.getMarchPromoProducts.mockResolvedValue(mockResponseDto);

			const result = await controller.getMarchPromoProducts(queryDto);

			expect(result).toEqual(mockResponseDto);
			expect(mockService.getMarchPromoProducts).toHaveBeenCalledWith({
				limit: 10,
				categoryId: 521,
			});
