import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { ForecastedTrendingProductsService } from '@modules/db/forecasted-trending-products/forecasted-trending-products.service';
import { ITrendingProductsBase } from '@modules/db/forecasted-trending-products/types/forecasted-trending-products.base.interface';
import { IStylesMvBase } from '@modules/db/styles-mv/types/styles-mv.base.interface';
import { ProductHydrationService } from '@modules/product-hydration/product-hydration.service';
import { PromosService } from '@modules/rest/promos/promos.service';

import { IRelatedProduct } from '@interfaces/related-product.interface';

describe('PromosService (E2E)', () => {
	let service: PromosService;
	let mockForecastedTrendingProductsService: jest.Mocked<ForecastedTrendingProductsService>;
	let mockProductHydrationService: jest.Mocked<ProductHydrationService>;

	const createMockTrendingProduct = (
		styleId: number,
		score: number,
	): ITrendingProductsBase => ({
		_id: `trending-${styleId}`,
		style_id: Number(styleId),
		predicted_orders: Array(30).fill(score),
		total_predicted_orders: score * 30,
		is_latest: true,
		is_active: true,
		trend_score: score,
		trending_reason: 'high_orders',
		forecast_start_date: '2024-01-01',
		forecast_end_date: '2024-01-30',
		forecast_days: 30,
		created_at: new Date('2024-01-01'),
		updated_at: new Date('2024-01-01'),
	});

	const createMockRelatedProduct = (styleId: number): IRelatedProduct => ({
		color: 1521505 + styleId,
		link: `/products/test-${styleId}`,
		sizing: 'One Size',
		sizes: ['One Size'],
		min_qty: 25,
		complement_badge: null,
		rating_score: '4.5',
		rating_count: '100',
		name: `Product ${styleId}`,
		style_id: styleId,
		decoration_method: 'screen',
		primary_category_id: 37,
		primary_category_name: 'Tote Bags',
		default_quote_qty: 100,
		style_type: 'non-apparel',
		image_src: `https://example.com/product-${styleId}.jpg`,
		broad_category_names: ['Bags'],
		sub_category_names: ['Tote Bags'],
		turn_time: 14,
		rush_turn_time: 7,
		default_unit_prices: [
			{ algorithm: 'default-2022-03-24', quantity: 100, price: '25.95' },
		],
		brand: [],
	});

	const createMockStylesMvBase = (styleId: number): IStylesMvBase => ({
		_id: `mv-${styleId}`,
		style_id: styleId,
		product_id: styleId,
		name: `Product ${styleId}`,
		link: `/products/test-${styleId}`,
		sizes: ['One Size'],
		colors: [
			{
				id: 1521505 + styleId,
				name: 'Natural',
				rbgs: [{ R: 255, G: 255, B: 255 }],
				image_url: `https://example.com/product-${styleId}.jpg`,
			},
		],
		no_minimum: false,
		min_qty: 25,
		minimum_quantity: 25,
		rating_score: 4.5,
		rating_count: 100,
		decoration_method: 'screen',
		features: null,
		general_comments: null,
		manufacturer: null,
		price_level: 1,
		product_type: 'product',
		condensed_features: null,
		primary_category_id: 37,
		primary_category_name: 'Tote Bags',
		default_quote_qty: 100,
		style_type: 'non-apparel',
		style_card_image_url: `https://example.com/product-${styleId}.jpg`,
		broad_category_names: ['Bags'],
		sub_category_names: ['Tote Bags'],
		turn_time: 14,
		rush_turn_time: 7,
		default_unit_prices: [
			{ algorithm: 'default-2022-03-24', quantity: 100, price: '25.95' },
		],
		brand: null,
		status: 'active',
		created_at: new Date('2024-01-01'),
		updated_at: new Date('2024-01-01'),
		deleted_at: null,
	});

	beforeEach(async () => {
		mockForecastedTrendingProductsService = {
			getTrendingProductsByCategory: jest.fn(),
			getTrendingProductsByCategoryAndStyleIds: jest.fn(),
		} as unknown as jest.Mocked<ForecastedTrendingProductsService>;

		mockProductHydrationService = {
			hydrateProductsWithColors: jest.fn(),
			getProductsByBrands: jest.fn(),
			convertMvColorsToProductColors: jest.fn(),
		} as unknown as jest.Mocked<ProductHydrationService>;

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				PromosService,
				{
					provide: ForecastedTrendingProductsService,
					useValue: mockForecastedTrendingProductsService,
				},
				{
					provide: ProductHydrationService,
					useValue: mockProductHydrationService,
				},
			],
		}).compile();

		service = module.get<PromosService>(PromosService);

		jest.spyOn(Logger.prototype, 'debug').mockImplementation(() => {
			return undefined;
		});
		jest.spyOn(Logger.prototype, 'error').mockImplementation(() => {
			return undefined;
		});
		jest.spyOn(Logger.prototype, 'warn').mockImplementation(() => {
			return undefined;
		});
		jest.spyOn(Logger.prototype, 'log').mockImplementation(() => {
			return undefined;
		});
	});

	afterEach(() => {
		jest.clearAllMocks();
		jest.restoreAllMocks();
	});

	describe('getHatPromoProducts - Full Integration', () => {
		it('should successfully integrate trending and brand products for hats category', async () => {
			const trendingData = [
				createMockTrendingProduct(111111, 100),
				createMockTrendingProduct(222222, 80),
			];

			const allProducts = [
				createMockRelatedProduct(111111),
				createMockRelatedProduct(222222),
			];
			const mvRecordsMap = new Map<number, IStylesMvBase>();
			allProducts.forEach((p) =>
				mvRecordsMap.set(p.style_id, createMockStylesMvBase(p.style_id)),
			);

			const brandProducts = [
				createMockRelatedProduct(666666),
				createMockRelatedProduct(777777),
			];
			const brandMvRecordsMap = new Map<number, IStylesMvBase>();
			brandProducts.forEach((p) =>
				brandMvRecordsMap.set(p.style_id, createMockStylesMvBase(p.style_id)),
			);

			mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockResolvedValue(
				trendingData,
			);
			mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
				products: allProducts,
				mvRecords: mvRecordsMap,
			});
			mockProductHydrationService.getProductsByBrands.mockResolvedValue({
				products: brandProducts,
				mvRecords: brandMvRecordsMap,
			});
			mockProductHydrationService.convertMvColorsToProductColors.mockReturnValue([]);

			const result = await service.getHatPromoProducts(20);

			expect(result.totalCount).toBeLessThanOrEqual(20);
			expect(result.products.length).toBe(result.totalCount);
			expect(result.promotionalCount).toBe(0);
			expect(
				mockForecastedTrendingProductsService.getTrendingProductsByCategory,
			).toHaveBeenCalledWith({ categoryId: 1, limit: 100 });
			expect(mockProductHydrationService.getProductsByBrands).toHaveBeenCalled();
		});

		it('should use hat promo brands list', async () => {
			mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockResolvedValue(
				[],
			);
			mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
				products: [],
				mvRecords: new Map(),
			});
			mockProductHydrationService.getProductsByBrands.mockResolvedValue({
				products: [],
				mvRecords: new Map(),
			});

			await service.getHatPromoProducts(20);

			expect(mockProductHydrationService.getProductsByBrands).toHaveBeenCalledWith({
				brands: [
					'Adidas',
					'Columbia',
					'Imperial',
					'Legacy',
					'Locale',
					'Pukka',
					'Swannies',
					'Under Armour',
					'Vineyard Vines',
					'Core365',
					'Team365',
				],
				limit: 100,
				categoryId: 1,
			});
		});

		it('should pass categoryId filter for hat category', async () => {
			const brandProducts = [createMockRelatedProduct(111111)];
			const brandMvRecordsMap = new Map<number, IStylesMvBase>();
			brandProducts.forEach((p) =>
				brandMvRecordsMap.set(p.style_id, createMockStylesMvBase(p.style_id)),
			);

			mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockResolvedValue(
				[],
			);
			mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
				products: [],
				mvRecords: new Map(),
			});
			mockProductHydrationService.getProductsByBrands.mockResolvedValue({
				products: brandProducts,
				mvRecords: brandMvRecordsMap,
			});
			mockProductHydrationService.convertMvColorsToProductColors.mockReturnValue([]);

			const result = await service.getHatPromoProducts(20);

			expect(mockProductHydrationService.getProductsByBrands).toHaveBeenCalledWith(
				expect.objectContaining({ categoryId: 1 }),
			);
			expect(result.boostedBrandCount).toBe(1);
		});

		it('should use 30% brand boosting for hat promo (6 out of 20)', async () => {
			const brandProducts = Array.from({ length: 10 }, (_, i) =>
				createMockRelatedProduct(600000 + i),
			);
			const brandMvRecordsMap = new Map<number, IStylesMvBase>();
			brandProducts.forEach((p) =>
				brandMvRecordsMap.set(p.style_id, createMockStylesMvBase(p.style_id)),
			);

			mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockResolvedValue(
				[],
			);
			mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
				products: [],
				mvRecords: new Map(),
			});
			mockProductHydrationService.getProductsByBrands.mockResolvedValue({
				products: brandProducts,
				mvRecords: brandMvRecordsMap,
			});
			mockProductHydrationService.convertMvColorsToProductColors.mockReturnValue([]);

			const result = await service.getHatPromoProducts(20);

			expect(result.boostedBrandCount).toBe(6);
		});

		it('should handle errors gracefully', async () => {
			mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockRejectedValue(
				new Error('Service error'),
			);

			await expect(service.getHatPromoProducts(20)).rejects.toThrow();
			expect(Logger.prototype.error).toHaveBeenCalledWith(
				expect.stringContaining('Error fetching hat promo products'),
			);
		});

		it('should handle empty results', async () => {
			mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockResolvedValue(
				[],
			);
			mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
				products: [],
				mvRecords: new Map(),
			});
			mockProductHydrationService.getProductsByBrands.mockResolvedValue({
				products: [],
				mvRecords: new Map(),
			});

			const result = await service.getHatPromoProducts(20);

			expect(result.totalCount).toBe(0);
			expect(result.trendingCount).toBe(0);
			expect(result.promotionalCount).toBe(0);
			expect(result.boostedBrandCount).toBe(0);
		});

		it('should use default limit when not provided', async () => {
			mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockResolvedValue(
				[],
			);
			mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
				products: [],
				mvRecords: new Map(),
			});
			mockProductHydrationService.getProductsByBrands.mockResolvedValue({
				products: [],
				mvRecords: new Map(),
			});

			const result = await service.getHatPromoProducts();

			expect(result).toBeDefined();
			expect(result.totalCount).toBeLessThanOrEqual(20);
		});
	});

	describe('getMarchPromoProducts - Full Integration', () => {
		it('should successfully return trending products from curated march list', async () => {
			const trendingData = [
				createMockTrendingProduct(349500, 100),
				createMockTrendingProduct(891500, 80),
				createMockTrendingProduct(264200, 60),
			];

			const products = [
				createMockRelatedProduct(349500),
				createMockRelatedProduct(891500),
				createMockRelatedProduct(264200),
			];
			const mvRecordsMap = new Map<number, IStylesMvBase>();
			products.forEach((p) =>
				mvRecordsMap.set(p.style_id, createMockStylesMvBase(p.style_id)),
			);

			mockForecastedTrendingProductsService.getTrendingProductsByCategoryAndStyleIds.mockResolvedValue(
				trendingData,
			);
			mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
				products,
				mvRecords: mvRecordsMap,
			});
			mockProductHydrationService.convertMvColorsToProductColors.mockReturnValue([]);

			const result = await service.getMarchPromoProducts({ limit: 20 });

			expect(result.totalCount).toBe(3);
			expect(result.products.length).toBe(3);
			expect(result.trendingCount).toBe(3);
			expect(result.promotionalCount).toBe(0);
			expect(result.boostedBrandCount).toBe(0);
			expect(
				mockForecastedTrendingProductsService.getTrendingProductsByCategoryAndStyleIds,
			).toHaveBeenCalledWith({
				categoryId: 8,
				styleIds: expect.arrayContaining([349500, 891500, 264200]),
				limit: 100,
			});
		});

		it('should use default category ID 8 when not provided', async () => {
			mockForecastedTrendingProductsService.getTrendingProductsByCategoryAndStyleIds.mockResolvedValue(
				[],
			);
			mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
				products: [],
				mvRecords: new Map(),
			});

			await service.getMarchPromoProducts({});

			expect(
				mockForecastedTrendingProductsService.getTrendingProductsByCategoryAndStyleIds,
