import { Controller, Get, HttpCode, HttpStatus, Query } from '@nestjs/common';
import { ApiOkResponse, ApiOperation, ApiTags } from '@nestjs/swagger';

import { AprilPromoQueryDto } from '@modules/rest/promos/dto/april-promo-query.dto';
import { MarchPromoQueryDto } from '@modules/rest/promos/dto/march-promo-query.dto';
import { PromoQueryDto } from '@modules/rest/promos/dto/promo-query.dto';
import { PromoResponseDto } from '@modules/rest/promos/dto/promo-response.dto';
import { PromosService } from '@modules/rest/promos/promos.service';

@ApiTags('Promos')
@Controller()
export class PromosController {
	constructor(private readonly promosService: PromosService) {}

	@Get('hat-promo')
	@HttpCode(HttpStatus.OK)
	@ApiOperation({
		summary: 'Get hat promo products',
		description:
			'Returns a 90/10 blend of trending products and promotional products for Hat promo deals (Hats category only), with priority brand boosting (Adidas, Columbia, Imperial, Legacy, Locale, Pukka, Swannies, Under Armour, Vineyard Vines, Core365, Team365).',
	})
	@ApiOkResponse({
		description: 'Successfully retrieved hat promo products',
		type: PromoResponseDto,
	})
	async getHatPromoProducts(@Query() query: PromoQueryDto): Promise<PromoResponseDto> {
		return await this.promosService.getHatPromoProducts(query.limit);
	}

	@Get('march-promo')
	@HttpCode(HttpStatus.OK)
	@ApiOperation({
		summary: 'Get march promo products',
		description:
			'Returns trending products from a curated list of promotional products, filtered by category. Allowed categories: 218 (Promotional Products), 8 (Pens & Office Supplies), 188 (Technology), 521 (Pens & Writing), 920 (Stationery), 405 (Stickers & Magnets).',
	})
	@ApiOkResponse({
		description: 'Successfully retrieved march promo products',
		type: PromoResponseDto,
	})
	async getMarchPromoProducts(
		@Query() query: MarchPromoQueryDto,
	): Promise<PromoResponseDto> {
		return await this.promosService.getMarchPromoProducts({
			limit: query.limit,
			categoryId: query.categoryId,
		});
	}

	@Get('april-promo')
	@HttpCode(HttpStatus.OK)
	@ApiOperation({
		summary: 'Get april promo products',
		description:
			'Returns trending products filtered by category for the April Drinkware & Bags promotion. Allowed categories: 477 (All Drinkware), 6 (Mugs), 43 (Water Bottles), 407 (Tumblers), 42 (Can Coolers), 58 (Glassware), 7 (Plastic Cups), 722 (KOOZIE), 482 (All Bags), 37 (Tote Bags), 203 (Backpacks), 73 (Drawstring Bags), 41 (Duffels & Gym Bags), 77 (Lunch Bags & Coolers), 238 (Fanny Packs), 450 (Pouches).',
	})
	@ApiOkResponse({
		description: 'Successfully retrieved april promo products',
		type: PromoResponseDto,
	})
	async getAprilPromoProducts(
		@Query() query: AprilPromoQueryDto,
	): Promise<PromoResponseDto> {
		return await this.promosService.getAprilPromoProducts({
			limit: query.limit,
			categoryId: query.categoryId,
		});
	}
}

