import { Injectable, Logger } from '@nestjs/common';

import { ForecastedTrendingProductsService } from '@modules/db/forecasted-trending-products/forecasted-trending-products.service';
import { ProductHydrationService } from '@modules/product-hydration/product-hydration.service';
import { PromoResponseDto } from '@modules/rest/promos/dto/promo-response.dto';

import { shuffleArray } from '@utils/array.util';
import { assignRandomColorToProduct } from '@utils/random-color-picker.util';

import { IRelatedProduct } from '@interfaces/related-product.interface';

import { LogExecution } from '@decorators/log-execution.decorator';

@Injectable()
export class PromosService {
	private readonly logger = new Logger(PromosService.name);

	private readonly HAT_PROMO_BRANDS = [
		'Adidas',
		'Columbia',
		'Imperial',
		'Legacy',
		'Locale',
		'Pukka',
		'Swannies',
		'Under Armour',
		'Vineyard Vines',
		'Core365',
		'Team365',
	];

	private readonly HAT_CATEGORY_ID = 1;

	private readonly MARCH_PROMO_DEFAULT_CATEGORY_ID = 8;

	private readonly APRIL_PROMO_DEFAULT_CATEGORY_ID = 477;

	private readonly MARCH_PROMO_PRODUCT_IDS = [
		349500, 891500, 264200, 1490500, 1557200, 354400, 268900, 947400, 1239000, 1513400,
		661300, 817300, 882800, 268500, 264100, 872300, 965200, 1132700, 818200, 1196100,
		268600, 103700, 370800, 1196500, 647600, 275800, 883000, 1540500, 1585800, 1720600,
		1718500, 661200, 1501700, 818300, 1618200, 873100, 835600, 1523000, 1120800, 1184200,
		1565500, 1617900, 350100, 1692900, 1163800, 1842500, 1565600, 1587800, 1885900,
		1630500, 1687400, 1686400, 1686300, 1863900, 1556600, 1192100, 1609500, 349800,
		2654000, 2622600, 2727700,
	];

	private readonly BRAND_PERCENTAGE = 0.3;

	constructor(
		private readonly forecastedTrendingProductsService: ForecastedTrendingProductsService,
		private readonly productHydrationService: ProductHydrationService,
	) {}

	@LogExecution({
		paramFormatter: ([limit]: [number]) => ({ limit }),
		responseFormatter: /* istanbul ignore next */ (res: PromoResponseDto) => ({
			totalCount: res.totalCount,
			trendingCount: res.trendingCount,
			boostedBrandCount: res.boostedBrandCount,
		}),
	})
	async getHatPromoProducts(limit = 20): Promise<PromoResponseDto> {
		try {
			const [trendingData, brandResult] = await Promise.all([
				this.forecastedTrendingProductsService.getTrendingProductsByCategory({
					categoryId: this.HAT_CATEGORY_ID,
					limit: 100,
				}),
				this.productHydrationService.getProductsByBrands({
					brands: this.HAT_PROMO_BRANDS,
					limit: 100,
					categoryId: this.HAT_CATEGORY_ID,
				}),
			]);

			const trendingIds = trendingData.map((p) => p.style_id);

			const { products: hydratedProducts, mvRecords } =
				await this.productHydrationService.hydrateProductsWithColors({
					styleIds: trendingIds,
				});

			const productsByStyleId = new Map(hydratedProducts.map((p) => [p.style_id, p]));

			const trendingProducts: IRelatedProduct[] = [];
			const brandProducts: IRelatedProduct[] = [];

			for (const trending of trendingData) {
				const product = productsByStyleId.get(trending.style_id);
				if (product) {
					const mv = mvRecords.get(trending.style_id);
					const colors = this.productHydrationService.convertMvColorsToProductColors({
						colors: mv?.colors ?? null,
					});
					const productWithRandomColor = assignRandomColorToProduct({
						product,
						availableColors: colors,
					});
					trendingProducts.push(productWithRandomColor);
				}
			}

			for (const product of brandResult.products) {
				const mv = brandResult.mvRecords.get(product.style_id);
				const colors = this.productHydrationService.convertMvColorsToProductColors({
					colors: mv?.colors ?? null,
				});
				const productWithRandomColor = assignRandomColorToProduct({
					product,
					availableColors: colors,
				});
				brandProducts.push(productWithRandomColor);
			}

			this.logger.debug(
				`Verified ${trendingProducts.length} trending products, ${brandProducts.length} brand products`,
			);

			const brandProductSet = new Set(brandProducts.map((p) => p.style_id));

			const nonBrandTrending = trendingProducts.filter(
				(p) => !brandProductSet.has(p.style_id),
			);

			const targetBrandCount = Math.min(
				brandProducts.length,
				Math.floor(limit * this.BRAND_PERCENTAGE),
			);
			const selectedBrands = shuffleArray({ array: brandProducts }).slice(
				0,
				targetBrandCount,
			);

			const selectedTrending = shuffleArray({ array: nonBrandTrending }).slice(
				0,
				Math.max(0, limit - selectedBrands.length),
			);

			const allProducts = [...selectedTrending, ...selectedBrands];
			const finalProducts = shuffleArray({ array: allProducts }).slice(0, limit);

			return {
				products: finalProducts,
				totalCount: finalProducts.length,
				trendingCount: selectedTrending.length + selectedBrands.length,
				promotionalCount: 0,
				boostedBrandCount: selectedBrands.length,
			};
		} catch (error) {
			this.logger.error(`Error fetching hat promo products: ${(error as Error).message}`);
			throw error;
		}
	}

	@LogExecution({
		paramFormatter: /* istanbul ignore next */ ([params]: [
			{ limit: number; categoryId: number }?,
		]) => ({
			limit: params?.limit,
			categoryId: params?.categoryId,
		}),
		responseFormatter: /* istanbul ignore next */ (res: PromoResponseDto) => ({
			totalCount: res.totalCount,
			trendingCount: res.trendingCount,
		}),
	})
	async getMarchPromoProducts({
		limit = 20,
		categoryId = this.MARCH_PROMO_DEFAULT_CATEGORY_ID,
	}: {
		limit?: number | undefined;
		categoryId?: number | undefined;
	} = {}): Promise<PromoResponseDto> {
		try {
			const trendingData =
				await this.forecastedTrendingProductsService.getTrendingProductsByCategoryAndStyleIds(
					{
						categoryId,
						styleIds: this.MARCH_PROMO_PRODUCT_IDS,
						limit: 100,
					},
				);

			const styleIds = trendingData.map((p) => p.style_id);

			const { products: hydratedProducts, mvRecords } =
				await this.productHydrationService.hydrateProductsWithColors({ styleIds });

			const productsByStyleId = new Map(hydratedProducts.map((p) => [p.style_id, p]));

			const trendingProducts: IRelatedProduct[] = [];

			for (const trending of trendingData) {
				const product = productsByStyleId.get(trending.style_id);
				if (product) {
					const mv = mvRecords.get(trending.style_id);
					const colors = this.productHydrationService.convertMvColorsToProductColors({
						colors: mv?.colors ?? null,
					});
					const productWithRandomColor = assignRandomColorToProduct({
						product,
						availableColors: colors,
					});
					trendingProducts.push(productWithRandomColor);
				}
			}

			const finalProducts = trendingProducts.slice(0, limit);

			return {
				products: finalProducts,
				totalCount: finalProducts.length,
				trendingCount: finalProducts.length,
				promotionalCount: 0,
				boostedBrandCount: 0,
			};
		} catch (error) {
			this.logger.error(
				`Error fetching march promo products: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	@LogExecution({
		paramFormatter: /* istanbul ignore next */ ([params]: [
			{ limit: number; categoryId: number }?,
		]) => ({
			limit: params?.limit,
			categoryId: params?.categoryId,
		}),
		responseFormatter: /* istanbul ignore next */ (res: PromoResponseDto) => ({
			totalCount: res.totalCount,
			trendingCount: res.trendingCount,
		}),
	})
	async getAprilPromoProducts({
		limit = 20,
		categoryId = this.APRIL_PROMO_DEFAULT_CATEGORY_ID,
	}: {
		limit?: number | undefined;
		categoryId?: number | undefined;
	} = {}): Promise<PromoResponseDto> {
		try {
			const trendingData =
				await this.forecastedTrendingProductsService.getTrendingProductsByCategory({
					categoryId,
					limit: 100,
				});

			const styleIds = trendingData.map((p) => p.style_id);

			const { products: hydratedProducts, mvRecords } =
				await this.productHydrationService.hydrateProductsWithColors({ styleIds });

			const productsByStyleId = new Map(hydratedProducts.map((p) => [p.style_id, p]));

			const trendingProducts: IRelatedProduct[] = [];

			for (const trending of trendingData) {
				const product = productsByStyleId.get(trending.style_id);
				if (product) {
					const mv = mvRecords.get(trending.style_id);
					const colors = this.productHydrationService.convertMvColorsToProductColors({
						colors: mv?.colors ?? null,
					});
					const productWithRandomColor = assignRandomColorToProduct({
						product,
						availableColors: colors,
					});
					trendingProducts.push(productWithRandomColor);
				}
			}

			const finalProducts = trendingProducts.slice(0, limit);

			return {
				products: finalProducts,
				totalCount: finalProducts.length,
				trendingCount: finalProducts.length,
				promotionalCount: 0,
				boostedBrandCount: 0,
			};
		} catch (error) {
			this.logger.error(
				`Error fetching april promo products: ${(error as Error).message}`,
			);
			throw error;
		}
	}
}

