import { ApiPropertyOptional } from '@nestjs/swagger';
import { Type } from 'class-transformer';
import { IsIn, IsInt, IsOptional, Max, Min } from 'class-validator';

const ALLOWED_APRIL_PROMO_CATEGORY_IDS = [
	477, 6, 43, 407, 42, 58, 7, 722, 482, 37, 203, 73, 41, 77, 238, 450,
];

export class AprilPromoQueryDto {
	@ApiPropertyOptional({
		description: 'Number of products to return',
		example: 20,
		default: 20,
	})
	@IsOptional()
	@Type(() => Number)
	@IsInt({ message: 'Limit must be an integer' })
	@Min(1, { message: 'Limit must be greater than 0' })
	@Max(100, { message: 'Limit must be less than or equal to 100' })
	limit?: number;

	@ApiPropertyOptional({
		description:
			'Category ID to filter products. Allowed: 477 (All Drinkware), 6 (Mugs), 43 (Water Bottles), 407 (Tumblers), 42 (Can Coolers), 58 (Glassware), 7 (Plastic Cups), 722 (KOOZIE), 482 (All Bags), 37 (Tote Bags), 203 (Backpacks), 73 (Drawstring Bags), 41 (Duffels & Gym Bags), 77 (Lunch Bags & Coolers), 238 (Fanny Packs), 450 (Pouches)',
		example: 477,
		default: 477,
	})
	@IsOptional()
	@Type(() => Number)
	@IsInt({ message: 'categoryId must be an integer' })
	@IsIn(ALLOWED_APRIL_PROMO_CATEGORY_IDS, {
		message: `categoryId must be one of: ${ALLOWED_APRIL_PROMO_CATEGORY_IDS.join(', ')}`,
	})
	categoryId?: number;
}

