 38→	private readonly MARCH_PROMO_PRODUCT_IDS = [
 39→		349500, 891500, 264200, 1490500, 1557200, 354400, 268900, 947400, 1239000, 1513400,
 40→		661300, 817300, 882800, 268500, 264100, 872300, 965200, 1132700, 818200, 1196100,
 41→		268600, 103700, 370800, 1196500, 647600, 275800, 883000, 1540500, 1585800, 1720600,
 42→		1718500, 661200, 1501700, 818300, 1618200, 873100, 835600, 1523000, 1120800, 1184200,
 43→		1565500, 1617900, 350100, 1692900, 1163800, 1842500, 1565600, 1587800, 1885900,
 44→		1630500, 1687400, 1686400, 1686300, 1863900, 1556600, 1192100, 1609500, 349800,
 45→		2654000, 2622600, 2727700,
 46→	];
 47→
 48→	private readonly BRAND_PERCENTAGE = 0.3;
 49→
 50→	constructor(
 51→		private readonly forecastedTrendingProductsService: ForecastedTrendingProductsService,
 52→		private readonly productHydrationService: ProductHydrationService,
 53→	) {}
 54→
 55→	@LogExecution({
 56→		paramFormatter: ([limit]: [number]) => ({ limit }),
 57→		responseFormatter: /* istanbul ignore next */ (res: PromoResponseDto) => ({
 58→			totalCount: res.totalCount,
 59→			trendingCount: res.trendingCount,
 60→			boostedBrandCount: res.boostedBrandCount,
 61→		}),
 62→	})
 63→	async getHatPromoProducts(limit = 20): Promise<PromoResponseDto> {
 64→		try {
 65→			const [trendingData, brandResult] = await Promise.all([
 66→				this.forecastedTrendingProductsService.getTrendingProductsByCategory({
 67→					categoryId: this.HAT_CATEGORY_ID,
 68→					limit: 100,
 69→				}),
 70→				this.productHydrationService.getProductsByBrands({
 71→					brands: this.HAT_PROMO_BRANDS,
 72→					limit: 100,
 73→					categoryId: this.HAT_CATEGORY_ID,
 74→				}),
 75→			]);
 76→
 77→			const trendingIds = trendingData.map((p) => p.style_id);
 78→
 79→			const { products: hydratedProducts, mvRecords } =
 80→				await this.productHydrationService.hydrateProductsWithColors({
 81→					styleIds: trendingIds,
 82→				});
 83→
 84→			const productsByStyleId = new Map(hydratedProducts.map((p) => [p.style_id, p]));
 85→
 86→			const trendingProducts: IRelatedProduct[] = [];
 87→			const brandProducts: IRelatedProduct[] = [];
 88→
 89→			for (const trending of trendingData) {
 90→				const product = productsByStyleId.get(trending.style_id);
 91→				if (product) {
 92→					const mv = mvRecords.get(trending.style_id);
 93→					const colors = this.productHydrationService.convertMvColorsToProductColors({
 94→						colors: mv?.colors ?? null,
 95→					});
 96→					const productWithRandomColor = assignRandomColorToProduct({
 97→						product,
 98→						availableColors: colors,
 99→					});
100→					trendingProducts.push(productWithRandomColor);
101→				}
102→			}
103→
104→			for (const product of brandResult.products) {
105→				const mv = brandResult.mvRecords.get(product.style_id);
106→				const colors = this.productHydrationService.convertMvColorsToProductColors({
107→					colors: mv?.colors ?? null,
108→				});
109→				const productWithRandomColor = assignRandomColorToProduct({
110→					product,
111→					availableColors: colors,
112→				});
113→				brandProducts.push(productWithRandomColor);
114→			}
115→
116→			this.logger.debug(
117→				`Verified ${trendingProducts.length} trending products, ${brandProducts.length} brand products`,
118→			);
119→
120→			const brandProductSet = new Set(brandProducts.map((p) => p.style_id));
121→
122→			const nonBrandTrending = trendingProducts.filter(
123→				(p) => !brandProductSet.has(p.style_id),
124→			);
125→
126→			const targetBrandCount = Math.min(
127→				brandProducts.length,
128→				Math.floor(limit * this.BRAND_PERCENTAGE),
129→			);
130→			const selectedBrands = shuffleArray({ array: brandProducts }).slice(
131→				0,
132→				targetBrandCount,
133→			);
134→
135→			const selectedTrending = shuffleArray({ array: nonBrandTrending }).slice(
136→				0,
137→				Math.max(0, limit - selectedBrands.length),
138→			);
139→
140→			const allProducts = [...selectedTrending, ...selectedBrands];
141→			const finalProducts = shuffleArray({ array: allProducts }).slice(0, limit);
142→
143→			return {
144→				products: finalProducts,
145→				totalCount: finalProducts.length,
146→				trendingCount: selectedTrending.length + selectedBrands.length,
147→				promotionalCount: 0,
148→				boostedBrandCount: selectedBrands.length,
149→			};
150→		} catch (error) {
151→			this.logger.error(`Error fetching hat promo products: ${(error as Error).message}`);
152→			throw error;
153→		}
154→	}
155→
156→	@LogExecution({
157→		paramFormatter: /* istanbul ignore next */ ([params]: [
158→			{ limit: number; categoryId: number }?,
159→		]) => ({
160→			limit: params?.limit,
161→			categoryId: params?.categoryId,
162→		}),
163→		responseFormatter: /* istanbul ignore next */ (res: PromoResponseDto) => ({
164→			totalCount: res.totalCount,
165→			trendingCount: res.trendingCount,
166→		}),
167→	})
168→	async getMarchPromoProducts({
169→		limit = 20,
170→		categoryId = this.MARCH_PROMO_DEFAULT_CATEGORY_ID,
171→	}: {
172→		limit?: number | undefined;
173→		categoryId?: number | undefined;
174→	} = {}): Promise<PromoResponseDto> {
175→		try {
176→			const trendingData =
177→				await this.forecastedTrendingProductsService.getTrendingProductsByCategoryAndStyleIds(
178→					{
179→						categoryId,
180→						styleIds: this.MARCH_PROMO_PRODUCT_IDS,
181→						limit: 100,
182→					},
183→				);
184→
185→			const styleIds = trendingData.map((p) => p.style_id);
186→
187→			const { products: hydratedProducts, mvRecords } =
188→				await this.productHydrationService.hydrateProductsWithColors({ styleIds });
189→
190→			const productsByStyleId = new Map(hydratedProducts.map((p) => [p.style_id, p]));
191→
192→			const trendingProducts: IRelatedProduct[] = [];
193→
194→			for (const trending of trendingData) {
195→				const product = productsByStyleId.get(trending.style_id);
196→				if (product) {
197→					const mv = mvRecords.get(trending.style_id);
198→					const colors = this.productHydrationService.convertMvColorsToProductColors({
199→						colors: mv?.colors ?? null,
200→					});
201→					const productWithRandomColor = assignRandomColorToProduct({
202→						product,
203→						availableColors: colors,
204→					});
205→					trendingProducts.push(productWithRandomColor);
206→				}
207→			}
208→
209→			const finalProducts = trendingProducts.slice(0, limit);
210→
211→			return {
212→				products: finalProducts,
213→				totalCount: finalProducts.length,
214→				trendingCount: finalProducts.length,
215→				promotionalCount: 0,
216→				boostedBrandCount: 0,
217→			};
218→		} catch (error) {
219→			this.logger.error(
220→				`Error fetching march promo products: ${(error as Error).message}`,
221→			);
222→			throw error;
223→		}
224→	}
225→
226→	@LogExecution({
227→		paramFormatter: /* istanbul ignore next */ ([params]: [
228→			{ limit: number; categoryId: number }?,
229→		]) => ({
230→			limit: params?.limit,
231→			categoryId: params?.categoryId,
232→		}),
233→		responseFormatter: /* istanbul ignore next */ (res: PromoResponseDto) => ({
