	it('should successfully return trending products for april promo', async () => {
		const trendingData = [
			createMockTrendingProduct(100001, 100),
			createMockTrendingProduct(100002, 80),
			createMockTrendingProduct(100003, 60),
		];

		const products = [
			createMockRelatedProduct(100001),
			createMockRelatedProduct(100002),
			createMockRelatedProduct(100003),
		];
		const mvRecordsMap = new Map<number, IStylesMvBase>();
		products.forEach((p) =>
			mvRecordsMap.set(p.style_id, createMockStylesMvBase(p.style_id)),
		);

		mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockResolvedValue(
			trendingData,
		);
		mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
			products,
			mvRecords: mvRecordsMap,
		});
		mockProductHydrationService.convertMvColorsToProductColors.mockReturnValue([]);

		const result = await service.getAprilPromoProducts({ limit: 20 });

		expect(result.totalCount).toBe(3);
		expect(result.products.length).toBe(3);
		expect(result.trendingCount).toBe(3);
		expect(result.promotionalCount).toBe(0);
		expect(result.boostedBrandCount).toBe(0);
		expect(
			mockForecastedTrendingProductsService.getTrendingProductsByCategory,
		).toHaveBeenCalledWith({
			categoryId: 477,
			limit: 100,
		});
	});

	it('should use default category ID 477 when not provided', async () => {
		mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockResolvedValue(
			[],
		);
		mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
			products: [],
			mvRecords: new Map(),
		});

		await service.getAprilPromoProducts({});

		expect(
			mockForecastedTrendingProductsService.getTrendingProductsByCategory,
		).toHaveBeenCalledWith(
			expect.objectContaining({
				categoryId: 477,
			}),
		);
	});

	it('should use provided category ID', async () => {
		mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockResolvedValue(
			[],
		);
		mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
			products: [],
			mvRecords: new Map(),
		});

		await service.getAprilPromoProducts({ categoryId: 43 });

		expect(
			mockForecastedTrendingProductsService.getTrendingProductsByCategory,
		).toHaveBeenCalledWith(
			expect.objectContaining({
				categoryId: 43,
			}),
		);
	});

	it('should handle empty results', async () => {
		mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockResolvedValue(
			[],
		);
		mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
			products: [],
			mvRecords: new Map(),
		});

		const result = await service.getAprilPromoProducts({ limit: 20 });

		expect(result.totalCount).toBe(0);
		expect(result.products).toHaveLength(0);
		expect(result.trendingCount).toBe(0);
	});

	it('should respect limit parameter', async () => {
