		mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockResolvedValue(
			trendingData,
		);
		mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
			products: [],
			mvRecords: new Map(),
		});

		const result = await service.getAprilPromoProducts({ limit: 20 });

		expect(result.totalCount).toBe(0);
		expect(result.trendingCount).toBe(0);
	});

	it('should handle MV record colors being null', async () => {
		const trendingData = [createMockTrendingProduct(100001, 100)];
		const products = [createMockRelatedProduct(100001)];

		const mvRecordWithNullColors = createMockStylesMvBase(100001);
