		mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockResolvedValue(
			trendingData,
		);
		mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
			products,
			mvRecords: mvRecordsMap,
		});
		mockProductHydrationService.convertMvColorsToProductColors.mockReturnValue([]);

		const result = await service.getAprilPromoProducts({ limit: 20 });

		expect(result.products.length).toBe(1);
		expect(
			mockProductHydrationService.convertMvColorsToProductColors,
		).toHaveBeenCalledWith({ colors: null });
	});

	it('should handle MV record not found in map', async () => {
		const trendingData = [createMockTrendingProduct(100001, 100)];
		const products = [createMockRelatedProduct(100001)];

		const mvRecordsMap = new Map<number, IStylesMvBase>();

		mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockResolvedValue(
			trendingData,
		);
		mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
			products,
			mvRecords: mvRecordsMap,
		});
		mockProductHydrationService.convertMvColorsToProductColors.mockReturnValue([]);

		const result = await service.getAprilPromoProducts({ limit: 20 });

		expect(result.products.length).toBe(1);
		expect(
			mockProductHydrationService.convertMvColorsToProductColors,
		).toHaveBeenCalledWith({ colors: null });
	});

	it('should work with all allowed category IDs', async () => {
		const allowedCategoryIds = [477, 6, 43, 407, 42, 58, 7, 722, 482, 37, 203, 73, 41, 77, 238, 450];

		for (const categoryId of allowedCategoryIds) {
			mockForecastedTrendingProductsService.getTrendingProductsByCategory.mockResolvedValue(
				[],
			);
			mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
				products: [],
				mvRecords: new Map(),
			});

			await service.getAprilPromoProducts({ categoryId });

			expect(
				mockForecastedTrendingProductsService.getTrendingProductsByCategory,
			).toHaveBeenCalledWith(expect.objectContaining({ categoryId }));
		}
	});
});

